from itertools import islice
from heapq import heappop, heappush
from sympy import primefactors, nextprime
def A356232_gen(): # generator of terms if first n terms of sequence is desired
    h, hset = [2], {2}
    yield 1
    while True:
        yield (m:=heappop(h))
        ps = primefactors(m)
        ps.append(nextprime(max(ps),2))
        for p in ps:
            mp = m*p
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
A356232_list = list(islice(A356232_gen(),40)) # _Chai Wah Wu_, Mar 21 2026

